def most_repeated_letters(text):
    # Initialize an empty dictionary to store letter frequencies
    letter_freq = {}

    # Iterate over each character in the text
    for char in text:
        # Check if the character is a letter
        if char.isalpha():
            # If the letter is already in the dictionary, increment its count
            if char in letter_freq:
                letter_freq[char] += 1
            # Otherwise, add the letter to the dictionary with a count of 1
            else:
                letter_freq[char] = 1

    # Check if the input string contains at least one letter
    if letter_freq:
        # Find the maximum frequency
        max_freq = max(letter_freq.values())

        # Create a dictionary to store the most repeated letter(s) and their frequency
        most_repeated = {}

        # Iterate over the letter frequencies
        for letter, freq in letter_freq.items():
            # If the frequency is equal to the maximum frequency, add it to the most_repeated dictionary
            if freq == max_freq:
                most_repeated[letter] = freq

        return most_repeated
    else:
        # Return an empty dictionary if the input string does not contain any letters
        return {}

