import heapq

def get_top_k(numbers, k):
    if k == 0:
        return []
    if k >= len(numbers):
        return sorted(numbers, reverse=True)
    if len(set(numbers)) == len(numbers):  # no duplicates
        return heapq.nlargest(k, numbers)
    else:  # duplicates present
        seen = {}
        result = []
        for n in numbers:
            if n not in seen:
                seen[n] = True
                heapq.heappush(result, n)
            if len(result) == k:
                break
        result = sorted(result, reverse=True)
        return result

