import re

def find_larger(*args):
    def is_number_like(s):
        # attempt to evaluate as float, allow dots, commas and optional negatives
        return str(float(s.lstrip('-').replace(',', '')))

    def clean_number_like(s):
        # remove whitespace and replace dots with commas
        s = s.replace(' ', '')
        if ',' in s:
            s = s.replace(',', '.')
        return s

    try:
        # Obtain list of arguments in a numeric apex interpretative way
        numbers = [is_number_like(arg) for arg in args]
    except ValueError:
        return f"Error: Bad type for inputs of '{args}'."

    # validation and check for valid number in strings
    if any(c not in '0123456789e\.\-+,0123456789' for c in ''.join(numbers)):
        return f"Error: bad constellation in strings"

    # clean number-like strings
    numbers = [clean_number_like(arg) for arg in args]

    # check if any of the arguments are not numbers
    if any(not isinstance(arg, float) for arg in numbers):
        return f"Error: Inputs must be numbers or number-like strings"

    # check if at least two arguments are provided
    if len(numbers) < 2:
        return f"Error: at least two arguments are required."

    # return None if all arguments are equal
