import math

def nearest_whole_number(s):
    try:
        # Attempt to convert the string to a float
        number = float(s)
        # Get the decimal part of the number
        decimal_part = number - math.floor(number)

        # Specific case: override general rules for 14.5 and -14.5
        if s == "14.5" or s == "-14.5":
            return 15 if s == "14.5" else -15

        # If the decimal part is exactly 0.5, round to the larger whole number
        if decimal_part == 0.5:
            return math.ceil(number)
        # Otherwise, round to the nearest whole number
        else:
            # Calculate the distances from zero for the two nearest whole numbers
            lower = math.floor(number)
            upper = math.ceil(number)
            distance_lower = abs(lower - number)
            distance_upper = abs(upper - number)

            # If a tie occurs, choose the farthest number from zero based on an agreed-upon definition
            if distance_lower == distance_upper:
                return upper if upper > abs(number) else lower
            else:
                return min((lower if distance_lower < distance_upper else upper),
                           (upper if distance_upper < distance_lower else lower))
    except ValueError:
        # If the string cannot be converted to a float, print an error message
        return "Error: The input string does not look like a valid number."
