    n = len(arr)
    graph = {}

    # Create a graph where each node has edges to itself, previous node, and next node
    for i in range(n):
        graph[i] = {}
        if i > 0:
            graph[i][i-1] = 1
        graph[i][i] = 0
        if i < n-1:
            graph[i][i+1] = 1

    # Use Dijkstra's algorithm to find the shortest path to reach all zeros
    distances = {i: float('inf') for i in range(n)}
    pq = [(0, 0)]
    visited = set()

    while pq:
        d, u = heapq.heappop(pq)
        if u not in visited:
            visited.add(u)
            for v in graph[u]:
                if v not in visited:
                    new_dist = distances[u] + graph[u][v] * (arr[u]^arr[v])
                    if new_dist < distances[v]:
                        distances[v] = new_dist
                        heapq.heappush(pq, (distances[v], v))

    # The minimum number of swaps is the minimum distance to reach all zeros
    return min(distances.values())

