def maximize_sum(nums, m, k):
    max_sum = 0
    for i in range(len(nums) - k + 1):
        window_sum = 0
        unique_nums = set()
        for j in range(k):
            window_sum += nums[i + j]
            unique_nums.add(nums[i + j])
            if len(unique_nums) >= m:
                max_sum = max(max_sum, window_sum)
    return max_sum if max_sum != 0 else 0
